const body = $json.body ?? {};

const message = body.message ?? body.user_message ?? '';
const sessionId = body.sessionId ?? null;
const context = body.context ?? {};

const state = body.state ?? {
  phase: 'qualification',
  name: null,
  budget: null,
  decision_role: null,
  timeline: null,
  lead_score: 0,
  booking_intent: false,
};

return [{ json: { message, sessionId, context, state } }];

const message = ($json.message ?? '').toString();
const state = $json.state ?? {};

const weekdayRe = /(montag|dienstag|mittwoch|donnerstag|freitag|samstag|sonntag|monday|tuesday|wednesday|thursday|friday|saturday|sunday)/i;
const timeRe = /\b\d{1,2}(?:[:.]\d{2})?\s*(?:uhr|o\s*'?clock|am|pm)\b/i;

const hasWeekday = weekdayRe.test(message);
const hasTime = timeRe.test(message);
const asksMeeting = /(termin|meeting|call|demo|beratung|kalender|booking|book)/i.test(message);

const hasPendingSlot = !!state?.pending_slot?.start && !!state?.pending_slot?.end;
const confirmRe = /\b(yes|yeah|yep|please|book|confirm|ok|okay|ja|bitte|mach|buche|buchen)\b/i;
const confirm_booking = hasPendingSlot && confirmRe.test(message) && !hasWeekday;

const booking_hint = asksMeeting || (hasWeekday && hasTime) || confirm_booking;

const system_prompt = `You are a lead-qualification assistant.
Return ONLY strict JSON with keys:
- reply: string
- booking_intent: boolean
- state_update: object (partial update)

Rules:
- booking_intent MUST be true ONLY if the user clearly asks to schedule a meeting/call/demo/appointment OR provides a concrete weekday+time for scheduling OR confirms booking for a previously proposed slot.
- If the user greets ("hi", "hallo") or asks general questions, booking_intent MUST be false.
- Keep reply short (1-3 sentences).
- state_update may include: phase,name,budget,decision_role,timeline,lead_score.
- Do not include markdown, backticks, or extra keys.`;

const user_prompt = `Current state:\n${JSON.stringify(state)}\n\nUser message:\n${message}`;

return [{ json: { message, state, booking_hint, confirm_booking, system_prompt, user_prompt, sessionId: $json.sessionId ?? null } }];

