const message = ($node["Build LLM Prompt"].json.message ?? '').toString();
const sessionId = $node["Build LLM Prompt"].json.sessionId ?? null;
const state = $node["Build LLM Prompt"].json.state ?? {};
const booking_hint = $node["Build LLM Prompt"].json.booking_hint === true;
const confirm_booking = $node["Build LLM Prompt"].json.confirm_booking === true;

if ($json?.error?.message) {
  return [{ json: { reply: `LLM Fehler: ${$json.error.message}`, booking_intent: false, state, message, sessionId } }];
}

if (!$json || typeof $json !== 'object' || !Array.isArray($json.choices)) {
  return [{ json: { reply: 'LLM ist gerade nicht verfügbar.', booking_intent: false, state, message, sessionId } }];
}

const content = $json.choices?.[0]?.message?.content;

let parsed;
try {
  parsed = JSON.parse((content ?? '').toString());
} catch {
  const fallbackReply = content ? content.toString() : 'LLM returned non-JSON.';
  return [{ json: { reply: fallbackReply, booking_intent: false, state, message, sessionId } }];
}

const modelBooking = parsed.booking_intent === true;
const booking_intent = booking_hint && (modelBooking || confirm_booking);
const state_update = parsed.state_update && typeof parsed.state_update === 'object' ? parsed.state_update : {};

const newState = { ...state, ...state_update, booking_intent };
const reply = typeof parsed.reply === 'string' ? parsed.reply : 'OK';

return [{ json: { reply, booking_intent, state: newState, message, sessionId } }];

const state = $node["Merge LLM Output"].json.state ?? {};
const message = ($node["Merge LLM Output"].json.message ?? '').toString();

const workdaysEnv = ($env.AGENT_WORKDAYS ?? '1,2,3,4,5').toString();
const allowedWorkdays = workdaysEnv
  .split(',')
  .map((s) => Number(s.trim()))
  .filter((n) => Number.isFinite(n));

function parseHHMM(value, fallback) {
  const m = value?.toString().trim().match(/^(\d{1,2}):(\d{2})$/);
  if (!m) return fallback;
  const hh = Math.min(23, Math.max(0, Number(m[1])));
  const mm = Math.min(59, Math.max(0, Number(m[2])));
  return { hh, mm };
}

const workStart = parseHHMM($env.AGENT_WORK_START, { hh: 9, mm: 0 });
const workEnd = parseHHMM($env.AGENT_WORK_END, { hh: 17, mm: 0 });
const horizonDays = Math.max(1, Number($env.AGENT_HORIZON_DAYS ?? 30) || 30);

const confirmRe = /\b(yes|yeah|yep|please|book|confirm|ok|okay|ja|bitte|mach|buche|buchen)\b/i;
const confirm = confirmRe.test(message);

function parseRequestedTime(text) {
  const lower = text.toLowerCase();
  const weekdayMap = {
    montag: 1,
    dienstag: 2,
    mittwoch: 3,
    donnerstag: 4,
    freitag: 5,
    samstag: 6,
    sonntag: 0,
    monday: 1,
    tuesday: 2,
    wednesday: 3,
    thursday: 4,
    friday: 5,
    saturday: 6,
    sunday: 0,
  };

  const weekday = Object.keys(weekdayMap).find((k) => new RegExp(`\\b${k}\\b`, 'i').test(lower));

  // Supports: "13 uhr", "11 o clock", "11 o'clock", "11am", "11 am", "11:30"
  const timeMatch = lower.match(/\\b(\\d{1,2})(?:[:.](\\d{2}))?\\s*(uhr|o\\s*'?clock|am|pm)?\\b/);

  if (!weekday || !timeMatch) return null;

  let hour = Math.min(23, Math.max(0, Number(timeMatch[1])));
  const minute = timeMatch[2] ? Math.min(59, Math.max(0, Number(timeMatch[2]))) : 0;
  const suffix = (timeMatch[3] || '').replace(/\\s+/g, '');

  if (suffix === 'pm' && hour < 12) hour += 12;
  if (suffix === 'am' && hour === 12) hour = 0;

  const targetDow = weekdayMap[weekday];
  const now = new Date();
  const todayDow = now.getDay();

  let addDays = (targetDow - todayDow + 7) % 7;

  const wantsNext = /\\bnext\\b/i.test(lower);

  const candidate = new Date(now.getFullYear(), now.getMonth(), now.getDate(), hour, minute, 0, 0);
  if (addDays === 0 && candidate.getTime() <= now.getTime()) addDays = 7;
  if (wantsNext && addDays === 0) addDays = 7;

  candidate.setDate(candidate.getDate() + addDays);
  return candidate;
}

const durationMin = 30;

const requested = parseRequestedTime(message);
if (!requested) {
  const pending = state?.pending_slot;
  if (confirm && pending?.start && pending?.end) {
    return [{
      json: {
        need_time: false,
        requested_start: pending.start,
        requested_end: pending.end,
        requested_label: pending.label ?? 'der gewünschte Termin',
        state,
      },
    }];
  }

  return [{
    json: {
      need_time: true,
      reply: 'Bitte nenn mir Tag + Uhrzeit innerhalb Mo–Fr 09:00–17:00 (z.B. "next Monday 11 o\'clock").',
      state,
    },
  }];
}

// Policy checks (workdays/hours/horizon)
const now = new Date();
const latest = new Date(now.getTime() + horizonDays * 24 * 60 * 60_000);

if (requested.getTime() > latest.getTime()) {
  return [{
    json: {
      need_time: true,
      reply: `Ich kann nur bis ${horizonDays} Tage im Voraus buchen. Bitte wähl einen früheren Termin (Mo–Fr 09:00–17:00).`,
      state,
    },
  }];
}

if (allowedWorkdays.length && !allowedWorkdays.includes(requested.getDay())) {
  return [{
    json: {
      need_time: true,
      reply: 'Ich kann nur Mo–Fr buchen. Nenn mir bitte einen Termin unter der Woche (09:00–17:00).',
      state,
    },
  }];
}

const startMinutes = requested.getHours() * 60 + requested.getMinutes();
const workStartMinutes = workStart.hh * 60 + workStart.mm;
const workEndMinutes = workEnd.hh * 60 + workEnd.mm;

if (startMinutes < workStartMinutes || startMinutes >= workEndMinutes) {
  return [{
    json: {
      need_time: true,
      reply: `Ich kann nur zwischen ${String(workStart.hh).padStart(2,'0')}:${String(workStart.mm).padStart(2,'0')} und ${String(workEnd.hh).padStart(2,'0')}:${String(workEnd.mm).padStart(2,'0')} buchen (Mo–Fr).`,
      state,
    },
  }];
}

const start = requested.toISOString();
const end = new Date(requested.getTime() + durationMin * 60_000).toISOString();
const label = requested.toLocaleString();

const newState = {
  ...state,
  pending_slot: { start, end, label, durationMin },
};

return [{ json: { need_time: false, requested_start: start, requested_end: end, requested_label: label, state: newState } }];

const state = $node["Parse Requested Slot"].json.state ?? {};
const label = $node["Parse Requested Slot"].json.requested_label ?? 'der gewünschte Termin';

if ($json?.error || $json?.message?.includes?.('credential') || $json?.name === 'NodeOperationError') {
  return [{ json: { reply: 'Konnte den Termin nicht eintragen (Credentials/Permissions fehlen). Bitte Google Calendar Credentials im Node setzen.', state, booking_intent: true } }];
}

const eventId = $json?.id;
const newState = { ...state, booked_event_id: eventId ?? null, booked_start: $node["Parse Requested Slot"].json.requested_start ?? null };

if (eventId) {
  return [{ json: { reply: `Gebucht: ${label} (30min).`, state: newState, booking_intent: true } }];
}

return [{ json: { reply: `Ich konnte ${label} leider nicht eintragen. Bitte versuch es nochmal.`, state: newState, booking_intent: true } }];

const state = $node["Parse Requested Slot"].json.state ?? {};
const label = $node["Parse Requested Slot"].json.requested_label ?? 'der gewünschte Termin';

if ($json?.error || $json?.message?.includes?.('credential') || $json?.name === 'NodeOperationError') {
  return [{ json: { reply: 'Kalender ist noch nicht verbunden (Google Calendar Credentials fehlen). Bitte in n8n Credentials im Node setzen.', state, booking_intent: true } }];
}

return [{ json: { reply: `${label} ist leider belegt. Nenn mir bitte eine Alternative (Tag + Uhrzeit).`, state, booking_intent: true } }];

const reply = $json.reply ?? 'OK';
const state = $json.state ?? {};
const booking_intent = $json.booking_intent ?? state.booking_intent ?? false;

return [{ json: { reply, state, booking_intent } }];
